const n={mongodb:{name:"MongoDB",icon:"M",color:"from-green-400 to-green-600",chapters:[{id:"intro",title:"MongoDB 简介",content:[{type:"heading",text:"什么是 MongoDB"},{type:"paragraph",text:"MongoDB 是一个基于分布式文件存储的数据库，由 C++ 语言编写。旨在为 WEB 应用提供可扩展的高性能数据存储解决方案。"},{type:"heading",text:"核心特点"},{type:"list",items:["<strong>文档型存储</strong>：数据以 BSON（Binary JSON）格式存储，灵活的文档模型","<strong>高性能</strong>：支持内存缓存，查询性能高","<strong>高可用性</strong>：支持自动故障转移和副本集","<strong>可扩展性</strong>：支持水平分片，轻松扩展","<strong>丰富的查询语言</strong>：支持丰富的查询表达式和聚合框架","<strong>无模式</strong>：集合不需要预定义结构，便于快速迭代"]},{type:"heading",text:"应用场景"},{type:"list",items:["内容管理系统（CMS）","实时大数据分析","移动应用后端","物联网（IoT）数据存储","社交网络应用","游戏数据存储"]}]},{id:"vs-mysql",title:"MongoDB vs MySQL",content:[{type:"heading",text:"核心区别对比"},{type:"table",headers:["对比项","MongoDB","MySQL"],rows:[["数据模型","文档型（无模式）","关系型（表结构）"],["存储格式","BSON（类JSON）","表格（行/列）"],["Schema灵活性","灵活，可随时修改字段","固定，需预先定义表结构"],["扩展方式","水平分片","垂直扩展为主"],["事务支持","4.0+支持多文档事务","完整ACID事务"],["查询语言","丰富的查询API","标准SQL"],["性能特点","高写入性能，适合大数据","复杂查询优化成熟"],["适用场景","半结构化/非结构化数据","结构化数据，复杂事务"]]},{type:"heading",text:"什么时候选择 MongoDB"},{type:"list",items:["数据结构经常变化，需要灵活的 Schema","需要存储大量的日志、事件流等半结构化数据","需要水平扩展能力","开发迭代速度快，Schema 不确定","需要高吞吐量的写入操作"]},{type:"heading",text:"什么时候选择 MySQL"},{type:"list",items:["数据结构稳定，关系复杂","需要强事务保证（如金融系统）","需要复杂的多表关联查询","团队更熟悉 SQL 生态","需要成熟的分析和报表工具"]}]},{id:"key-concepts",title:"核心概念",content:[{type:"heading",text:"基本概念对比"},{type:"paragraph",text:"理解 MongoDB 与关系型数据库的术语对应关系"},{type:"table",headers:["MongoDB","MySQL","说明"],rows:[["Database（数据库）","Database","数据库容器"],["Collection（集合）","Table","文档集合"],["Document（文档）","Row（行）","数据记录"],["Field（字段）","Column（列）","数据字段"],["Index（索引）","Index","提高查询效率"],["_id（主键）","Primary Key","唯一标识符"]]},{type:"heading",text:"BSON 数据类型"},{type:"list",items:["<strong>String</strong>：字符串","<strong>Integer</strong>：整数（32位/64位）","<strong>Double</strong>：浮点数","<strong>Boolean</strong>：布尔值","<strong>Array</strong>：数组","<strong>Object</strong>：嵌入式对象","<strong>Null</strong>：空值","<strong>Date</strong>：日期时间","<strong>ObjectId</strong>：对象ID（文档唯一标识）","<strong>Binary Data</strong>：二进制数据"]}]},{id:"crud-operations",title:"CRUD 操作",content:[{type:"heading",text:"创建文档 (Create)"},{type:"code",lang:"javascript",code:'// 插入单条文档\ndb.users.insertOne({\n  name: "张三",\n  age: 25,\n  email: "zhangsan@example.com",\n  tags: ["developer", "mongodb"],\n  createdAt: new Date()\n})\n\n// 插入多条文档\ndb.users.insertMany([\n  { name: "李四", age: 30, role: "admin" },\n  { name: "王五", age: 28, role: "user" }\n])'},{type:"heading",text:"读取文档 (Read)"},{type:"code",lang:"javascript",code:'// 查询所有文档\ndb.users.find()\n\n// 条件查询\ndb.users.find({ age: { $gte: 25 } })\n\n// 查询单个文档\ndb.users.findOne({ email: "zhangsan@example.com" })\n\n// 投影（只返回指定字段）\ndb.users.find({}, { name: 1, email: 1, _id: 0 })\n\n// 排序\ndb.users.find().sort({ age: -1 })\n\n// 分页\ndb.users.find().skip(10).limit(5)'},{type:"heading",text:"更新文档 (Update)"},{type:"code",lang:"javascript",code:'// 更新单个文档\ndb.users.updateOne(\n  { email: "zhangsan@example.com" },\n  { $set: { age: 26, updatedAt: new Date() } }\n)\n\n// 更新多个文档\ndb.users.updateMany(\n  { role: "user" },\n  { $set: { status: "active" } }\n)\n\n// 替换整个文档\ndb.users.replaceOne(\n  { email: "zhangsan@example.com" },\n  {\n    name: "张三",\n    age: 26,\n    email: "zhangsan@example.com",\n    role: "senior-developer"\n  }\n)'},{type:"heading",text:"删除文档 (Delete)"},{type:"code",lang:"javascript",code:'// 删除单个文档\ndb.users.deleteOne({ email: "zhangsan@example.com" })\n\n// 删除多个文档\ndb.users.deleteMany({ status: "inactive" })\n\n// 删除所有文档\ndb.users.deleteMany({})'}]},{id:"indexing",title:"索引",content:[{type:"heading",text:"索引概述"},{type:"paragraph",text:"索引可以显著提高查询性能，但会增加写入开销和存储空间。"},{type:"heading",text:"创建索引"},{type:"code",lang:"javascript",code:'// 创建单字段索引\ndb.users.createIndex({ email: 1 })\n\n// 创建复合索引\ndb.users.createIndex({ name: 1, age: -1 })\n\n// 创建唯一索引\ndb.users.createIndex({ email: 1 }, { unique: true })\n\n// 创建稀疏索引（只索引存在该字段的文档）\ndb.users.createIndex({ phone: 1 }, { sparse: true })\n\n// 创建文本索引（全文搜索）\ndb.articles.createIndex({ content: "text" })\n\n// 查看索引\ndb.users.getIndexes()\n\n// 删除索引\ndb.users.dropIndex("email_1")'},{type:"heading",text:"索引类型"},{type:"list",items:["<strong>单字段索引</strong>：对单个字段建立索引","<strong>复合索引</strong>：对多个字段组合建立索引","<strong>唯一索引</strong>：确保字段值唯一","<strong>稀疏索引</strong>：只索引包含该字段的文档","<strong>文本索引</strong>：支持文本搜索","<strong>地理空间索引</strong>：支持地理位置查询","<strong>哈希索引</strong>：基于哈希值的索引"]},{type:"heading",text:"索引优化建议"},{type:"list",items:["<strong>优先满足常用查询</strong>：根据查询频率和排序字段建立索引","<strong>覆盖索引</strong>：索引包含查询所需字段，避免回表","<strong>使用 hint()</strong>：强制使用特定索引进行查询优化","<strong>避免过多索引</strong>：过多索引会影响写入性能","<strong>定期审查</strong>：使用 db.collection.getIndexes() 和 explain() 检查索引使用情况"]}]},{id:"aggregation",title:"聚合框架",content:[{type:"heading",text:"聚合管道"},{type:"paragraph",text:"MongoDB 的聚合框架提供了强大的数据处理能力，通过管道操作符对数据进行转换和计算。"},{type:"code",lang:"javascript",code:'db.orders.aggregate([\n  // $match: 筛选文档\n  { $match: { status: "completed" } },\n\n  // $group: 分组统计\n  {\n    $group: {\n      _id: "$userId",\n      totalAmount: { $sum: "$amount" },\n      count: { $sum: 1 },\n      avgAmount: { $avg: "$amount" }\n    }\n  },\n\n  // $sort: 排序\n  { $sort: { totalAmount: -1 } },\n\n  // $limit: 限制结果数量\n  { $limit: 10 }\n])'},{type:"heading",text:"常用聚合操作符"},{type:"table",headers:["阶段","操作符","说明"],rows:[["$match","筛选条件","过滤文档，类似find()"],["$group","分组统计","按字段分组并计算聚合值"],["$sort","排序","对结果进行排序"],["$limit","限制数量","限制返回文档数量"],["$skip","跳过文档","跳过指定数量的文档"],["$project","字段投影","选择、重命名和转换字段"],["$unwind","展开数组","将数组字段展开为多个文档"],["$lookup","左连接","类似SQL的LEFT JOIN"]]},{type:"heading",text:"聚合表达式"},{type:"code",lang:"javascript",code:'// 数学表达式\n{ $sum: "$price" }      // 求和\n{ $avg: "$price" }      // 平均值\n{ $min: "$price" }      // 最小值\n{ $max: "$price" }      // 最大值\n\n// 条件表达式\n{\n  $cond: {\n    if: { $gte: ["$score", 60] },\n    then: "及格",\n    else: "不及格"\n  }\n}\n\n// 字符串表达式\n{ $concat: ["$firstName", " ", "$lastName"] }  // 字符串拼接\n{ $toLower: "$name" }     // 转小写\n{ $toUpper: "$name" }     // 转大写\n\n// 数组表达式\n{ $size: "$tags" }        // 数组长度\n{ $in: ["mongodb", "$tags"] }  // 是否包含元素'}]},{id:"replication",title:"副本集",content:[{type:"heading",text:"副本集概述"},{type:"paragraph",text:"副本集是一组维护相同数据集的 MongoDB 服务器，提供数据冗余和高可用性。"},{type:"heading",text:"副本集架构"},{type:"list",items:["<strong>Primary（主节点）</strong>：接收所有写操作","<strong>Secondary（从节点）</strong>：从主节点复制数据，提供读操作","<strong>Arbiter（仲裁节点）</strong>：参与选举，不存储数据"]},{type:"heading",text:"部署副本集"},{type:"code",lang:"bash",code:"# 启动三个 MongoDB 实例\nmongod --replSet rs0 --port 27017 --dbpath /data/db1\nmongod --replSet rs0 --port 27018 --dbpath /data/db2\nmongod --replSet rs0 --port 27019 --dbpath /data/db3\n\n# 启动仲裁节点\nmongod --replSet rs0 --port 27020 --dbpath /data/arbiter"},{type:"code",lang:"javascript",code:'// 启动 MongoDB 时指定副本集\nmongod --replSet rs0 --port 27017\n\n// 连接到 MongoDB 后初始化副本集\nrs.initiate({\n  _id: "rs0",\n  members: [\n    { _id: 0, host: "localhost:27017" },\n    { _id: 1, host: "localhost:27018" },\n    { _id: 2, host: "localhost:27019" }\n  ]\n})\n\n// 查看副本集状态\nrs.status()\n\n// 添加成员\nrs.add("localhost:27020")\n\n// 移除成员\nrs.remove("localhost:27020")'},{type:"heading",text:"读写分离"},{type:"code",lang:"javascript",code:'// 设置读偏好（客户端）\n// primary: 只从主节点读（默认）\n// primaryPreferred: 优先主节点\n// secondary: 只从节点读\n// secondaryPreferred: 优先从节点\n// nearest: 读延迟最低的节点\n\ndb.collection.find().readPref("secondary")'},{type:"heading",text:"副本集配置优化"},{type:"list",items:["<strong>优先级 (priority)</strong>：控制节点选举主节点的倾向","<strong>隐藏节点 (hidden)</strong>：用于备份/分析，避免对外提供服务","<strong>投票权 (votes)</strong>：通常设置为1，仲裁节点可设置为0","<strong>Oplog 大小</strong>：在高写入场景下适当增大以减少延迟","<strong>心跳间隔</strong>：默认2秒，可根据网络环境调整"]}]},{id:"sharding",title:"分片与扩展",content:[{type:"heading",text:"分片概述"},{type:"paragraph",text:"分片是 MongoDB 实现水平扩展的核心技术，将数据分散存储在多个服务器上。"},{type:"heading",text:"分片架构组件"},{type:"list",items:["<strong>Shard（分片服务器）</strong>：存储数据分片","<strong>Config Server（配置服务器）</strong>：存储集群元数据","<strong>Mongos（路由服务器）</strong>：请求路由，协调查询"]},{type:"heading",text:"分片键选择"},{type:"paragraph",text:"分片键决定了数据如何分布，选择合适的分片键至关重要。"},{type:"code",lang:"javascript",code:'// 启用分片\nsh.enableSharding("mydb")\n\n// 对集合进行分片\nsh.shardCollection("mydb.users", { userId: 1 })\n\n// 哈希分片（均匀分布）\nsh.shardCollection("mydb.logs", { _id: "hashed" })'},{type:"heading",text:"分片策略"},{type:"list",items:["<strong>范围分片</strong>：基于分片键值的范围分布数据","<strong>哈希分片</strong>：基于分片键哈希值均匀分布数据","<strong>区域分片</strong>：基于地理位置或自定义标签分布数据"]},{type:"heading",text:"分片管理"},{type:"code",lang:"javascript",code:'// 查看分片状态\nsh.status()\n\n// 添加分片服务器\nsh.addShard("rs1/localhost:27021,localhost:27022")\n\n// 重新平衡分片\nsh.startBalancer()\nsh.stopBalancer()\n\n// 查看分片分布\ndb.collection.getShardDistribution()'}]},{id:"transactions",title:"事务",content:[{type:"heading",text:"多文档事务"},{type:"paragraph",text:"MongoDB 4.0+ 支持多文档事务，确保多个文档操作的原子性。"},{type:"code",lang:"javascript",code:'// 启动事务会话\nconst session = db.getMongo().startSession()\n\nsession.startTransaction({\n  readConcern: { level: "snapshot" },\n  writeConcern: { w: "majority" }\n})\n\ntry {\n  // 在事务中执行操作\n  db.accounts.updateOne(\n    { _id: "account1" },\n    { $inc: { balance: -100 } },\n    { session }\n  )\n\n  db.accounts.updateOne(\n    { _id: "account2" },\n    { $inc: { balance: 100 } },\n    { session }\n  )\n\n  // 提交事务\n  session.commitTransaction()\n} catch (error) {\n  // 回滚事务\n  session.abortTransaction()\n} finally {\n  session.endSession()\n}'},{type:"heading",text:"事务限制"},{type:"list",items:["<strong>运行时间限制</strong>：默认60秒，可配置","<strong>数据大小限制</strong>：16MB（WiredTiger缓存大小）","<strong>操作数量限制</strong>：1000个操作","<strong>只读事务不支持</strong>：快照隔离","<strong>分片集群限制</strong>：某些操作不支持"]},{type:"heading",text:"ACID 属性"},{type:"table",headers:["属性","MongoDB实现","说明"],rows:[["原子性(Atomicity)","✓","事务中的操作要么全部成功，要么全部失败"],["一致性(Consistency)","✓","事务前后数据库保持一致状态"],["隔离性(Isolation)","快照隔离","事务间相互隔离，避免脏读、不可重复读、幻读"],["持久性(Durability)","✓","事务提交后数据持久化到磁盘"]]}]},{id:"security",title:"安全配置",content:[{type:"heading",text:"认证与授权"},{type:"code",lang:"javascript",code:'// 启用认证启动\nmongod --auth --keyFile /path/to/keyfile\n\n// 创建管理员用户\nuse admin\ndb.createUser({\n  user: "admin",\n  pwd: "password",\n  roles: ["userAdminAnyDatabase", "dbAdminAnyDatabase", "readWriteAnyDatabase"]\n})\n\n// 创建应用用户\nuse myapp\ndb.createUser({\n  user: "appuser",\n  pwd: "apppassword",\n  roles: ["readWrite"]\n})\n\n// 角色权限说明\n// read: 只读权限\n// readWrite: 读写权限\n// dbAdmin: 数据库管理权限\n// userAdmin: 用户管理权限\n// clusterAdmin: 集群管理权限'},{type:"heading",text:"TLS/SSL 加密"},{type:"code",lang:"bash",code:"# 生成证书\nopenssl req -new -x509 -days 365 -out mongodb.crt -keyout mongodb.key\n\n# 合并证书和私钥\ncat mongodb.key mongodb.crt > mongodb.pem\n\n# 启用 TLS 启动\nmongod --sslMode requireSSL --sslPEMKeyFile mongodb.pem"},{type:"heading",text:"网络安全"},{type:"code",lang:"javascript",code:"// 绑定特定 IP\nmongod --bind_ip 127.0.0.1,192.168.1.100\n\n// 禁用 HTTP 接口\nmongod --nohttpinterface\n\n// 设置最大连接数\nmongod --maxConns 1000"},{type:"heading",text:"审计日志"},{type:"code",lang:"javascript",code:'// 启用审计\nmongod --auditDestination file --auditFormat JSON --auditPath /var/log/mongodb/audit.log\n\n// 审计配置\ndb.createUser({\n  user: "auditor",\n  pwd: "auditpass",\n  roles: ["clusterAdmin"]\n})'}]},{id:"backup-recovery",title:"备份与恢复",content:[{type:"heading",text:"备份策略"},{type:"list",items:["<strong>逻辑备份</strong>：使用 mongoexport/mongoimport，灵活但慢","<strong>物理备份</strong>：直接复制数据文件，快但需要停止服务","<strong>副本集备份</strong>：从从节点备份，不影响主节点","<strong>分片集群备份</strong>：需要备份所有组件"]},{type:"heading",text:"使用 mongodump 备份"},{type:"code",lang:"bash",code:"# 备份整个数据库\nmongodump --db mydb --out /backup/$(date +%Y%m%d)\n\n# 备份特定集合\nmongodump --db mydb --collection users --out /backup/users\n\n# 压缩备份\nmongodump --db mydb --out /backup --gzip\n\n# 远程备份\nmongodump --host mongodb.example.com --port 27017 --db mydb --out /backup"},{type:"heading",text:"使用 mongorestore 恢复"},{type:"code",lang:"bash",code:"# 恢复数据库\nmongorestore --db mydb /backup/mydb\n\n# 恢复到不同数据库\nmongorestore --db newdb /backup/mydb\n\n# 从压缩备份恢复\nmongorestore --gzip --db mydb /backup/mydb\n\n# 恢复特定集合\nmongorestore --db mydb --collection users /backup/mydb/users"},{type:"heading",text:"自动化备份脚本"},{type:"code",lang:"bash",code:'#!/bin/bash\n\n# 备份脚本\nDB_NAME="mydb"\nBACKUP_DIR="/backup"\nDATE=$(date +%Y%m%d_%H%M%S)\n\nmkdir -p $BACKUP_DIR/$DATE\n\n# 执行备份\nmongodump --db=$DB_NAME --out=$BACKUP_DIR/$DATE --gzip\n\n# 清理7天前的备份\nfind $BACKUP_DIR -type d -mtime +7 -exec rm -rf {} +\n\necho "Backup completed: $BACKUP_DIR/$DATE"'}]},{id:"monitoring",title:"监控与维护",content:[{type:"heading",text:"监控指标"},{type:"list",items:["<strong>连接数</strong>：当前活跃连接数量","<strong>操作统计</strong>：读写操作的频率和延迟","<strong>内存使用</strong>：WiredTiger缓存和系统内存","<strong>磁盘I/O</strong>：读写操作的磁盘性能","<strong>副本集状态</strong>：主从同步延迟和健康状态","<strong>慢查询日志</strong>：识别性能瓶颈"]},{type:"heading",text:"数据库状态检查"},{type:"code",lang:"javascript",code:"// 服务器状态\ndb.serverStatus()\n\n// 数据库统计\ndb.stats()\n\n// 集合统计\ndb.collection.stats()\n\n// 副本集状态\nrs.status()\n\n// 分片状态\nsh.status()"},{type:"heading",text:"性能分析"},{type:"code",lang:"javascript",code:'// 启用性能分析器\ndb.setProfilingLevel(2, { slowms: 100 })\n\n// 查看慢查询\ndb.system.profile.find().sort({ ts: -1 }).limit(5)\n\n// 解释查询执行计划\ndb.collection.find({ field: "value" }).explain("executionStats")\n\n// 查看当前操作\ndb.currentOp()'},{type:"heading",text:"日志管理"},{type:"code",lang:"bash",code:'# 日志轮转\nmongod --logpath /var/log/mongodb/mongod.log \\\n       --logRotate reopen\n\n# 日志级别设置\ndb.setLogLevel(1, "query")\ndb.setLogLevel(0, "query")  # 恢复默认'}]},{id:"modeling",title:"数据建模",content:[{type:"heading",text:"文档设计原则"},{type:"list",items:["<strong>内嵌 vs 引用</strong>：根据访问模式选择","<strong>读写比例</strong>：读多场景优先内嵌","<strong>数据局部性</strong>：相关数据放在一起","<strong>原子性需求</strong>：需要事务的数据考虑引用","<strong>文档大小限制</strong>：单个文档不超过16MB"]},{type:"heading",text:"内嵌文档模式"},{type:"code",lang:"javascript",code:'// 用户资料（内嵌地址）\n{\n  _id: ObjectId("..."),\n  name: "张三",\n  email: "zhangsan@example.com",\n  addresses: [\n    {\n      type: "home",\n      street: "北京市朝阳区",\n      city: "北京",\n      country: "中国"\n    },\n    {\n      type: "work",\n      street: "北京市海淀区",\n      city: "北京",\n      country: "中国"\n    }\n  ]\n}\n\n// 博客文章（内嵌评论）\n{\n  _id: ObjectId("..."),\n  title: "MongoDB 最佳实践",\n  content: "...",\n  author: {\n    name: "李四",\n    email: "lisi@example.com"\n  },\n  comments: [\n    {\n      author: "王五",\n      content: "很好",\n      createdAt: ISODate("2023-01-01")\n    }\n  ]\n}'},{type:"heading",text:"引用模式"},{type:"code",lang:"javascript",code:'// 用户集合\n{\n  _id: ObjectId("user1"),\n  name: "张三",\n  email: "zhangsan@example.com"\n}\n\n// 订单集合（引用用户）\n{\n  _id: ObjectId("order1"),\n  userId: ObjectId("user1"),  // 引用用户ID\n  items: [...],\n  total: 100\n}\n\n// 使用 $lookup 进行关联查询\ndb.orders.aggregate([\n  {\n    $lookup: {\n      from: "users",\n      localField: "userId",\n      foreignField: "_id",\n      as: "user"\n    }\n  }\n])'},{type:"heading",text:"数据建模最佳实践"},{type:"list",items:["<strong>优先考虑读取模式</strong>：设计时优先考虑应用的主要查询模式","<strong>避免过度规范化</strong>：MongoDB 不需要严格的规范化设计","<strong>使用合适的分片键</strong>：为分片集群选择合适的分片键","<strong>预留字段</strong>：为未来可能的变化预留一些字段","<strong>定期审查</strong>：随着应用发展定期审查数据模型"]}]},{id:"advanced-features",title:"高级特性",content:[{type:"heading",text:"变更流 (Change Streams)"},{type:"paragraph",text:"变更流允许应用程序监听数据库的实时变更，实现事件驱动架构。"},{type:"code",lang:"javascript",code:"// 监听集合变更\nconst changeStream = db.collection.watch()\n\nchangeStream.on('change', (change) => {\n  console.log('变更类型:', change.operationType)\n  console.log('文档ID:', change.documentKey._id)\n\n  if (change.operationType === 'insert') {\n    console.log('新文档:', change.fullDocument)\n  }\n})\n\n// 监听特定操作\ndb.collection.watch([\n  { $match: { operationType: { $in: ['insert', 'update'] } } }\n])\n\n// 带过滤的变更流\ndb.collection.watch([\n  {\n    $match: {\n      $and: [\n        { operationType: 'update' },\n        { 'updateDescription.updatedFields.status': { $exists: true } }\n      ]\n    }\n  }\n])"},{type:"heading",text:"地理空间查询"},{type:"code",lang:"javascript",code:'// 创建地理空间索引\ndb.places.createIndex({ location: "2dsphere" })\n\n// 插入地理位置数据\ndb.places.insertMany([\n  {\n    name: "天安门",\n    location: {\n      type: "Point",\n      coordinates: [116.3974, 39.9093]  // [经度, 纬度]\n    }\n  },\n  {\n    name: "故宫",\n    location: {\n      type: "Point",\n      coordinates: [116.3974, 39.9163]\n    }\n  }\n])\n\n// 附近查询\ndb.places.find({\n  location: {\n    $near: {\n      $geometry: {\n        type: "Point",\n        coordinates: [116.4074, 39.9093]\n      },\n      $maxDistance: 1000  // 米\n    }\n  }\n})\n\n// 多边形查询\ndb.places.find({\n  location: {\n    $geoWithin: {\n      $geometry: {\n        type: "Polygon",\n        coordinates: [[\n          [116.3, 39.8],\n          [116.5, 39.8],\n          [116.5, 40.0],\n          [116.3, 40.0],\n          [116.3, 39.8]\n        ]]\n      }\n    }\n  }\n})'},{type:"heading",text:"全文搜索"},{type:"code",lang:"javascript",code:'// 创建文本索引\ndb.articles.createIndex({ title: "text", content: "text" })\n\n// 文本搜索\ndb.articles.find({\n  $text: { $search: "MongoDB 教程" }\n})\n\n// 带分数的文本搜索\ndb.articles.find(\n  { $text: { $search: "MongoDB" } },\n  { score: { $meta: "textScore" } }\n).sort({ score: { $meta: "textScore" } })\n\n// 排除特定词\ndb.articles.find({\n  $text: { $search: "MongoDB -MySQL" }\n})'},{type:"heading",text:"GridFS 大文件存储"},{type:"code",lang:"javascript",code:"// 存储大文件\nconst fs = require('fs')\nconst mongo = require('mongodb')\n\n// 连接数据库\nconst client = await mongo.MongoClient.connect('mongodb://localhost:27017')\nconst db = client.db('mydb')\nconst bucket = new mongo.GridFSBucket(db)\n\n// 上传文件\nconst uploadStream = bucket.openUploadStream('large-file.pdf')\nfs.createReadStream('./large-file.pdf').pipe(uploadStream)\n\n// 下载文件\nconst downloadStream = bucket.openDownloadStreamByName('large-file.pdf')\ndownloadStream.pipe(fs.createWriteStream('./downloaded-file.pdf'))"}]}]},mysql:{name:"MySQL",icon:"M",color:"from-blue-400 to-blue-600",chapters:[{id:"intro",title:"MySQL 简介",content:[{type:"heading",text:"什么是 MySQL"},{type:"paragraph",text:"MySQL 是最流行的开源关系型数据库管理系统，由 Oracle 公司维护。"},{type:"heading",text:"核心特点"},{type:"list",items:["<strong>关系型数据库</strong>：基于表结构的数据存储","<strong>ACID 事务</strong>：保证数据一致性和完整性","<strong>高性能</strong>：优化的查询引擎和索引系统","<strong>可扩展性</strong>：支持读写分离和分库分表","<strong>丰富的生态</strong>：广泛的工具和社区支持","<strong>多存储引擎</strong>：InnoDB、MyISAM 等多种引擎"]}]},{id:"installation",title:"安装与配置",content:[{type:"heading",text:"安装 MySQL"},{type:"code",lang:"bash",code:"# Ubuntu/Debian\nsudo apt update\nsudo apt install mysql-server\n\n# CentOS/RHEL\nsudo yum install mysql-server\nsudo systemctl start mysqld\n\n# macOS (使用 Homebrew)\nbrew install mysql\nbrew services start mysql\n\n# Docker\ndocker run --name mysql -e MYSQL_ROOT_PASSWORD=password -d mysql:8.0"},{type:"heading",text:"基本配置"},{type:"code",lang:"bash",code:"# 编辑配置文件\nsudo vim /etc/mysql/mysql.conf.d/mysqld.cnf\n\n# 常用配置项\n[mysqld]\n# 端口\nport = 3306\n\n# 数据目录\ndatadir = /var/lib/mysql\n\n# 字符集\ncharacter-set-server = utf8mb4\ncollation-server = utf8mb4_unicode_ci\n\n# InnoDB 配置\ninnodb_buffer_pool_size = 1G\ninnodb_log_file_size = 256M\n\n# 最大连接数\nmax_connections = 100"}]},{id:"basic-operations",title:"基本操作",content:[{type:"heading",text:"连接数据库"},{type:"code",lang:"bash",code:"# 连接本地数据库\nmysql -u root -p\n\n# 连接远程数据库\nmysql -h 192.168.1.100 -u username -p\n\n# 指定数据库连接\nmysql -u root -p database_name"},{type:"heading",text:"数据库操作"},{type:"code",lang:"sql",code:"-- 创建数据库\nCREATE DATABASE mydb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;\n\n-- 查看所有数据库\nSHOW DATABASES;\n\n-- 选择数据库\nUSE mydb;\n\n-- 删除数据库\nDROP DATABASE mydb;"},{type:"heading",text:"表操作"},{type:"code",lang:"sql",code:"-- 创建表\nCREATE TABLE users (\n  id INT PRIMARY KEY AUTO_INCREMENT,\n  username VARCHAR(50) NOT NULL UNIQUE,\n  email VARCHAR(100) NOT NULL,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;\n\n-- 查看表结构\nDESCRIBE users;\nSHOW CREATE TABLE users;\n\n-- 修改表结构\nALTER TABLE users ADD COLUMN age INT;\nALTER TABLE users MODIFY COLUMN email VARCHAR(150);\n\n-- 删除表\nDROP TABLE users;"}]}]}};function e(e){return n[e]||null}function t(){return Object.keys(n)}export{e as a,t as g};
